import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { ArrowRight, Sparkles, Truck, Shield, RotateCcw, Star } from 'lucide-react';
import { productAPI } from '../api';
import '../styles/HomePage.css';

export default function HomePage() {
  const [featured, setFeatured] = useState([]);
  const [categories, setCategories] = useState([]);

  useEffect(() => {
    productAPI.getFeatured().then(r => setFeatured(r.data.data || [])).catch(() => {});
    productAPI.getCategories().then(r => setCategories(r.data.data || [])).catch(() => {});
  }, []);

  return (
    <div className="home-page">
      {/* Hero */}
      <section className="hero">
        <div className="hero-bg" />
        <div className="hero-content">
          <div className="hero-badge"><Sparkles size={14} /> AI-Powered Shopping</div>
          <h1 className="hero-title">Discover Products<br /><span className="gradient-text">Curated by AI</span></h1>
          <p className="hero-subtitle">Smart recommendations, instant answers, and a personalized shopping experience powered by Claude AI.</p>
          <div className="hero-actions">
            <Link to="/products" className="btn btn-primary btn-lg">Shop Now <ArrowRight size={18} /></Link>
            <Link to="/tracking" className="btn btn-secondary btn-lg">Track Order</Link>
          </div>
        </div>
      </section>

      {/* Features */}
      <section className="features-strip">
        {[
          { icon: Truck, title: 'Free Shipping', desc: 'On orders over $50' },
          { icon: Shield, title: 'Secure Payment', desc: 'Multiple options' },
          { icon: RotateCcw, title: '30-Day Returns', desc: 'Hassle-free' },
          { icon: Sparkles, title: 'AI Assistant', desc: 'Shop smarter' },
        ].map(({ icon: Icon, title, desc }) => (
          <div key={title} className="feature-item">
            <div className="feature-icon"><Icon size={22} /></div>
            <div><h4>{title}</h4><p>{desc}</p></div>
          </div>
        ))}
      </section>

      {/* Categories */}
      {categories.length > 0 && (
        <section className="page-container">
          <div className="section-header">
            <h2>Categories</h2>
            <Link to="/products" className="see-all">View All <ArrowRight size={16} /></Link>
          </div>
          <div className="category-grid">
            {categories.map(cat => (
              <Link key={cat} to={`/products?category=${cat}`} className="category-card">
                <span>{cat}</span>
              </Link>
            ))}
          </div>
        </section>
      )}


      {/* Featured Products */}
      <section className="page-container">
        <div className="section-header">
          <h2>Featured Products</h2>
          <Link to="/products" className="see-all">View All <ArrowRight size={16} /></Link>
        </div>
        <div className="product-grid">
          {featured.map(p => (
            <Link key={p.id} to={`/products/${p.id}`} className="product-card">
              <div className="product-img-wrap">
                <img src={p.imageUrl} alt={p.name} loading="lazy" />
                {p.originalPrice && (
                  <div className="product-badge-sale">
                    {Math.round((1 - p.price / p.originalPrice) * 100)}% OFF
                  </div>
                )}
              </div>
              <div className="product-info">
                <span className="product-category">{p.category}</span>
                <h3 className="product-name">{p.name}</h3>
                <div className="product-rating">
                  <Star size={14} fill="var(--warning)" color="var(--warning)" />
                  <span>{p.rating}</span>
                  <span className="review-count">({p.reviewCount})</span>
                </div>
                <div className="product-pricing">
                  <span className="current-price">${p.price}</span>
                  {p.originalPrice && <span className="original-price">${p.originalPrice}</span>}
                </div>
              </div>
            </Link>
          ))}
        </div>
      </section>
    </div>
  );
}
